    const map = new Map<number, number[]>();

    // Precompute all pairs of points and their slopes
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const [x1, y1] = points[i];
            const [x2, y2] = points[j];
            const dy = y2 - y1;
            const dx = x2 - x1;
            let gcdVal = gcd(Math.abs(dy), Math.abs(dx));
            const slope = `${dy / gcdVal},${dx / gcdVal}`;
